        "q_circus" to mapOf(Lang.EN to "How many spectators could the Circus Maximus hold for chariot races?", Lang.IT to "Quanti spettatori poteva contenere il Circo Massimo per le corse dei carri?", Lang.ES to "¿Cuántos espectadores podía albergar el Circo Máximo para las carreras de carros?", Lang.PL to "Ilu widzów mógł pomieścić Circus Maximus na wyścigi rydwanów?"),
        "q_catacombs" to mapOf(Lang.EN to "TRUE or FALSE: Rome's underground catacombs stretch over 150 kilometers.", Lang.IT to "VERO o FALSO: Le catacombe sotterranee di Roma si estendono per oltre 150 chilometri.", Lang.ES to "VERDADERO o FALSO: Las catacumbas subterráneas de Roma se extienden por más de 150 kilómetros.", Lang.PL to "PRAWDA czy FAŁSZ: Podziemne katakumby Rzymu rozciągają się na ponad 150 kilometrów."),
        "q_borghese" to mapOf(Lang.EN to "Which sculptor created the famous 'Apollo and Daphne' in the Borghese Gallery?", Lang.IT to "Quale scultore ha creato il famoso 'Apollo e Dafne' nella Galleria Borghese?", Lang.ES to "¿Qué escultor creó el famoso 'Apolo y Dafne' en la Galería Borghese?", Lang.PL to "Który rzeźbiarz stworzył słynne 'Apollo i Dafne' w Galerii Borghese?"),
