        "onboard_explore_title" to mapOf(Lang.EN to "EXPLORE ROME", Lang.IT to "ESPLORA ROMA", Lang.ES to "EXPLORA ROMA", Lang.PL to "ODKRYWAJ RZYM"),
        "onboard_explore_desc" to mapOf(Lang.EN to "Discover 250+ curated places — restaurants, gelato shops, monuments, water fountains and hidden gems. Use the interactive map with Night Mode for bars & clubs.", Lang.IT to "Scopri oltre 250 luoghi selezionati — ristoranti, gelaterie, monumenti, fontanelle e gemme nascoste. Usa la mappa interattiva con Modalità Notte per bar e club.", Lang.ES to "Descubre más de 250 lugares seleccionados — restaurantes, heladerías, monumentos, fuentes y joyas ocultas. Usa el mapa interactivo con Modo Noche para bares y clubs.", Lang.PL to "Odkryj ponad 250 starannie wybranych miejsc — restauracje, lodziarnie, zabytki, fontanny i ukryte perełki. Użyj interaktywnej mapy z Trybem Nocnym dla barów i klubów."),
        "onboard_quests_title" to mapOf(Lang.EN to "CONQUER QUESTS", Lang.IT to "CONQUISTA LE MISSIONI", Lang.ES to "CONQUISTA MISIONES", Lang.PL to "PODBIJAJ QUESTY"),
        "onboard_quests_desc" to mapOf(Lang.EN to "Complete 20 interactive Roman quests — trivia, emoji puzzles, true/false challenges and fill-in-the-blank. Unlock secret places by completing all quests!", Lang.IT to "Completa 20 quiz romani interattivi — trivia, puzzle emoji, vero/falso e riempi lo spazio. Sblocca luoghi segreti completando tutti i quiz!", Lang.ES to "Completa 20 misiones romanas interactivas — trivia, puzzles de emojis, verdadero/falso y completa el espacio. ¡Desbloquea lugares secretos completando todas las misiones!", Lang.PL to "Ukończ 20 interaktywnych questów — quizy, zagadki emoji, prawda/fałsz i uzupełnianie luk. Odblokuj sekretne miejsca kończąc wszystkie questy!"),
        "onboard_learn_title" to mapOf(Lang.EN to "LEARN ITALIAN", Lang.IT to "IMPARA L'ITALIANO", Lang.ES to "APRENDE ITALIANO", Lang.PL to "UCZ SIĘ WŁOSKIEGO"),
        "onboard_learn_desc" to mapOf(Lang.EN to "Swipe through Italian flashcards — 10 free per day. Visit monuments to earn bonus words. Collect passport stamps by taking photos at real locations!", Lang.IT to "Scorri le flashcard italiane — 10 gratis al giorno. Visita i monumenti per guadagnare parole bonus. Colleziona timbri visitando luoghi reali!", Lang.ES to "Desliza las tarjetas de italiano — 10 gratis al día. Visita monumentos para ganar palabras bonus. ¡Colecciona sellos visitando lugares reales!", Lang.PL to "Przeglądaj włoskie fiszki — 10 za darmo dziennie. Odwiedzaj zabytki, aby zdobyć bonusowe słowa. Zbieraj pieczątki robiąc zdjęcia w prawdziwych lokalizacjach!"),
        "start_exploring" to mapOf(Lang.EN to "START EXPLORING", Lang.IT to "INIZIA A ESPLORARE", Lang.ES to "EMPEZAR A EXPLORAR", Lang.PL to "ZACZNIJ ODKRYWAĆ"),
