        "upgrade_for_more" to mapOf(Lang.EN to "Upgrade for premium features", Lang.IT to "Aggiorna per funzioni premium", Lang.ES to "Mejora para funciones premium", Lang.PL to "Ulepsz aby uzyskać funkcje premium"),
        "faq_title" to mapOf(Lang.EN to "❓ FREQUENTLY ASKED QUESTIONS", Lang.IT to "❓ DOMANDE FREQUENTI", Lang.ES to "❓ PREGUNTAS FRECUENTES", Lang.PL to "❓ NAJCZĘŚCIEJ ZADAWANE PYTANIA"),
        "faq_q1" to mapOf(Lang.EN to "What is Vojo PRO?", Lang.IT to "Cos'è Vojo PRO?", Lang.ES to "¿Qué es Vojo PRO?", Lang.PL to "Czym jest Vojo PRO?"),
        "faq_a1" to mapOf(Lang.EN to "Vojo PRO (€4.99 one-time) unlocks premium avatars, all 20 interactive quests, night mode with bars & clubs, offline maps, ad-free experience, and unlimited Italian flashcards.", Lang.IT to "Vojo PRO (€4.99 una tantum) sblocca avatar premium, tutti i 20 quiz interattivi, modalità notte con bar e club, mappe offline, niente pubblicità e flashcard italiane illimitate.", Lang.ES to "Vojo PRO (€4.99 único pago) desbloquea avatares premium, las 20 misiones interactivas, modo noche con bares y clubs, mapas offline, sin publicidad y tarjetas de italiano ilimitadas.", Lang.PL to "Vojo PRO (€4.99 jednorazowo) odblokowuje awatary premium, wszystkie 20 interaktywnych questów, tryb nocny z barami i klubami, mapy offline, brak reklam i nieograniczone fiszki włoskie."),
        "faq_q2" to mapOf(Lang.EN to "How do quests work?", Lang.IT to "Come funzionano le missioni?", Lang.ES to "¿Cómo funcionan las misiones?", Lang.PL to "Jak działają questy?"),
        "faq_a2" to mapOf(Lang.EN to "Quests are interactive challenges about Rome's history — trivia, emoji puzzles, true/false, and fill-in-the-blank. Complete all 20 to unlock 4 secret hidden places on the map!", Lang.IT to "Le missioni sono sfide interattive sulla storia di Roma — trivia, puzzle emoji, vero/falso e riempi lo spazio. Completa tutti i 20 per sbloccare 4 luoghi segreti nascosti sulla mappa!", Lang.ES to "Las misiones son desafíos interactivos sobre la historia de Roma — trivia, puzzles de emojis, verdadero/falso y completar espacios. ¡Completa las 20 para desbloquear 4 lugares secretos!", Lang.PL to "Questy to interaktywne wyzwania o historii Rzymu — quizy, zagadki emoji, prawda/fałsz i uzupełnianie luk. Ukończ wszystkie 20, aby odblokować 4 sekretne miejsca na mapie!"),
        "faq_q3" to mapOf(Lang.EN to "How do I earn bonus swipes?", Lang.IT to "Come guadagno swipe bonus?", Lang.ES to "¿Cómo gano deslizamientos bonus?", Lang.PL to "Jak zdobyć bonusowe przeciągnięcia?"),
        "faq_a3" to mapOf(Lang.EN to "Visit any monument on the map and take a photo when you're within 500 meters. Each photo adds a stamp to your passport and gives you +1 bonus swipe for the Italian flashcards!", Lang.IT to "Visita qualsiasi monumento sulla mappa e scatta una foto quando sei entro 500 metri. Ogni foto aggiunge un timbro al passaporto e ti dà +1 swipe bonus per le flashcard!", Lang.ES to "Visita cualquier monumento en el mapa y toma una foto cuando estés a menos de 500 metros. ¡Cada foto añade un sello a tu pasaporte y te da +1 deslizamiento bonus!", Lang.PL to "Odwiedź dowolny zabytek na mapie i zrób zdjęcie, gdy jesteś w odległości 500 metrów. Każde zdjęcie dodaje pieczątkę do paszportu i daje +1 bonusowe przeciągnięcie do fiszek!"),
        "faq_q4" to mapOf(Lang.EN to "Is my data private?", Lang.IT to "I miei dati sono privati?", Lang.ES to "¿Mis datos son privados?", Lang.PL to "Czy moje dane są prywatne?"),
        "faq_a4" to mapOf(Lang.EN to "Yes! All your data (photos, progress, preferences) is stored locally on your device. We don't collect or share any personal information. The only network requests are for map tiles and weather data.", Lang.IT to "Sì! Tutti i tuoi dati (foto, progressi, preferenze) sono memorizzati localmente sul tuo dispositivo. Non raccogliamo né condividiamo informazioni personali. Le uniche richieste di rete sono per le mappe e i dati meteo.", Lang.ES to "¡Sí! Todos tus datos (fotos, progreso, preferencias) se almacenan localmente en tu dispositivo. No recopilamos ni compartimos información personal. Las únicas solicitudes de red son para mapas y datos meteorológicos.", Lang.PL to "Tak! Wszystkie Twoje dane (zdjęcia, postępy, preferencje) są przechowywane lokalnie na urządzeniu. Nie zbieramy ani nie udostępniamy żadnych informacji osobistych. Jedyne zapytania sieciowe dotyczą map i pogody."),
        "faq_q5" to mapOf(Lang.EN to "How do offline maps work?", Lang.IT to "Come funzionano le mappe offline?", Lang.ES to "¿Cómo funcionan los mapas offline?", Lang.PL to "Jak działają mapy offline?"),
        "faq_a5" to mapOf(Lang.EN to "PRO users can download a 112MB offline map of Rome. Once downloaded, you can browse all points of interest without an internet connection — perfect for exploring without roaming charges!", Lang.IT to "Gli utenti PRO possono scaricare una mappa offline di Roma da 112MB. Una volta scaricata, puoi esplorare tutti i punti di interesse senza connessione internet — perfetto per esplorare senza costi roaming!", Lang.ES to "Los usuarios PRO pueden descargar un mapa offline de Roma de 112MB. Una vez descargado, puedes explorar todos los puntos de interés sin conexión — ¡perfecto para explorar sin cargos de roaming!", Lang.PL to "Użytkownicy PRO mogą pobrać mapę offline Rzymu (112MB). Po pobraniu możesz przeglądać wszystkie punkty zainteresowania bez internetu — idealne do zwiedzania bez opłat roamingowych!"),
        "faq_q6" to mapOf(Lang.EN to "What are Hidden Gems?", Lang.IT to "Cosa sono le Gemme Nascoste?", Lang.ES to "¿Qué son las Joyas Ocultas?", Lang.PL to "Czym są Ukryte Perełki?"),
        "faq_a6" to mapOf(Lang.EN to "Hidden Gems are ultra-local, off-the-beaten-path spots that most tourists never find. They're marked with a special gold tag on the map. Think: where real Romans actually eat, drink, and hang out.", Lang.IT to "Le Gemme Nascoste sono posti ultra-locali fuori dai sentieri battuti che la maggior parte dei turisti non trova mai. Sono contrassegnati con un tag dorato speciale sulla mappa. Pensa: dove i veri romani mangiano, bevono e si rilassano.", Lang.ES to "Las Joyas Ocultas son lugares ultra-locales fuera de las rutas turísticas que la mayoría nunca encuentra. Están marcados con una etiqueta dorada especial en el mapa. Piensa: donde los verdaderos romanos comen, beben y salen.", Lang.PL to "Ukryte Perełki to ultra-lokalne miejsca z dala od turystycznych szlaków, których większość turystów nigdy nie znajduje. Są oznaczone specjalnym złotym tagiem na mapie. Pomyśl: gdzie prawdziwi Rzymianie jedzą, piją i spędzają czas."),
        "faq_q7" to mapOf(Lang.EN to "How do notifications work?", Lang.IT to "Come funzionano le notifiche?", Lang.ES to "¿Cómo funcionan las notificaciones?", Lang.PL to "Jak działają powiadomienia?"),
        "faq_a7" to mapOf(Lang.EN to "Vojo sends smart notifications: morning Italian phrases, golden hour photo alerts when weather is perfect, evening exploration tips, and inspirational Rome quotes — all automatically translated to your language!", Lang.IT to "Vojo invia notifiche intelligenti: frasi italiane mattutine, avvisi per la golden hour quando il meteo è perfetto, consigli serali per esplorare e citazioni ispiratrici su Roma — tutto tradotto automaticamente nella tua lingua!", Lang.ES to "Vojo envía notificaciones inteligentes: frases italianas matutinas, alertas de hora dorada cuando el clima es perfecto, consejos nocturnos para explorar y citas inspiradoras sobre Roma — ¡todo traducido automáticamente a tu idioma!", Lang.PL to "Vojo wysyła inteligentne powiadomienia: poranne frazy włoskie, alerty złotej godziny gdy pogoda jest idealna, wieczorne wskazówki do zwiedzania i inspirujące cytaty o Rzymie — wszystko automatycznie przetłumaczone na Twój język!"),
